function ModelWonderland:WonderlandOpsReq(type,moreinfo,callback)

    local isSelectReq = type == ModelWonderland.EVENT_SELECT_GRID
    if isSelectReq and self:IsProtect() then
        return
    end
    local data =
    {
        layerIndex = self:GetCurLayer() + 1,
        gridIndex = tonumber(moreinfo),
    }
    if isSelectReq then
        self._selectGrid = data
        self._selectCallBack = callback
    end


    self:AddReqProtect()

    local pb = LProtoHelper.CreateProto(LProtoIds.WonderlandOpsReq)
    pb.type = type
    if moreinfo then
        pb.moreinfo = moreinfo
    end

    SendMessage(pb,LProtoIds.WonderlandOpsReq)

end

