function ModelWonderland:OnWonderlandScenePageResp(pb)
    if not self._layerInfos then
        self._layerInfos = {}

    end
    local type = pb.type
    if type == 0 then
        self._layerInfos = {}
        self._affectDataList ={}
    end

    self._gridInfos = {}
    self._layerList= {}

    self._themeId = pb.info.id
    self._countdown = pb.info.countDown
    local mapInfo = pb.info.mapInfo

    local oldState = self._isInMap
    self._isInMap = pb.info.haveMap == 1

    self._themeIdArr = pb.info.themeIdArr

    self._pattern = pb.info.pattern
    self._viaPatternType = pb.info.viaPatternType
    self._maxThemeType = pb.info.maxThemeType


    local selGridChange = false

    if self._isInMap then
        self._freeRebornCnt = mapInfo.freeCount

        self._affectDataList ={} --清除影响的格子，重新计算

        self._layerIndex = mapInfo.tierIndex
        self._gridIndex = mapInfo.gridIndex
        local oldBout = self._bout
        self._bout = mapInfo.bout

        self._themeBuff = mapInfo.themeBuff
        self._maxLayerIndex = mapInfo.maxTierIndex

        self:SetThemeMoreInfo(mapInfo.themeMoreinfo)

        self._passAwardState = mapInfo.passAwardState

        for k,v in ipairs(mapInfo.tierInfo) do

            local layerIndex = v.tierIndex
            local layer =
            {
                layerIndex = layerIndex,
            }
            local list = {}
            for k1,v1 in ipairs(v.gridInfo) do
                local grid = StructWonderlandGrid:New()
                grid:CreateByPb(v1)
                grid:SetLayerIndex(layerIndex)
                table.insert(list,grid)
            end
            table.sort(list,function(a,b) return a:GetGridIndex()< b:GetGridIndex() end)
            layer.grids = list

            self._layerInfos[layerIndex] = layer
        end


        local list = {}
        local defaultGrid = StructWonderlandGrid:New()
        defaultGrid:SetLayerIndex(0)
        defaultGrid:SetStatus(StructWonderlandGrid.PASSED)
        local defaultLayer =
        {
            layerIndex = 0,
            grids = {defaultGrid},
        }


        local gridKey = self:FormatGridKey(0,0)
        self._gridInfos[gridKey] = defaultGrid

        local oldSelGrid = self._selGrid
        self._selGrid = nil

        table.insert(list,defaultLayer)
        for k,v in pairs(self._layerInfos) do
            table.insert(list,v)
            for k1,v1 in pairs(v.grids) do
                local layerIndex = v.layerIndex
                local gridIndex = v1.gridIndex
                gridKey = self:FormatGridKey(layerIndex,gridIndex)
                self._gridInfos[gridKey] = v1

                local state = v1:GetStatus()
                if state == StructWonderlandGrid.SELECTED then
                    self._selGrid = v1
                end

                for k2,v2 in ipairs(v1.eventList) do
                    for k3,v3 in ipairs(v2.scopes) do
                        local lIndex = v3.tierIndex
                        local gIndex = v3.gridIndex
                        local gridKey  = self:FormatGridKey(lIndex,gIndex)
                        local eventId = v2.eventId
                        local affectList = self._affectDataList[gridKey]
                        if not affectList then
                            affectList = {}
                            self._affectDataList[gridKey] =affectList
                        end
                        table.insert(affectList,eventId)
                    end

                    local eventId = v2.eventId
                    local eventCfg = self:GetEventConfig(eventId)
                    local type = eventCfg.type
                    if type == ModelWonderland.EVENT_BEAST then
                        self._beastEvent = v2
                    end
                end
            end
        end

        local curGridKey = self:FormatGridKey(self._layerIndex,self._gridIndex)
        if self._curGridKey then
            local oldGrid = self._gridInfos[self._curGridKey]
            if oldGrid then
                oldGrid:SetStatus(StructWonderlandGrid.PASSED)
            end
        end

        local grid = self._gridInfos[curGridKey]
        if grid then
            grid:SetStatus(StructWonderlandGrid.PLAYER)
        end
        self._curGridKey = curGridKey


        table.sort(list,function (a,b) return a.layerIndex> b.layerIndex end)

        self._layerList = list

        self:RecordOldState()


        if oldBout ~= self._bout then
            self:OnBoutChange()
        end

        selGridChange= self:CheckSelGridEventChange(oldSelGrid,self._selGrid)
        FireEvent(EventNames.ON_DEST_REWARD_REFRESH)

    else
        self._selGrid = nil
        self._curGridKey = nil
        self._themeMoreInfo = nil
        self._beastEventData = nil
        self._beastEvent = nil
        self:ClearOldRecord()
    end



    if oldState == true and self._isInMap == false then
        local wnd = GF.FindFirstWndByName("UIEden")
        if wnd then
            GF.OpenWndBottom("UIEdenFront")
            wnd:WndClose()
            GF.ChangeMap("LCityMap")
        end
    end


    if not self._isInMap then
        FireEvent(EventNames.ON_WONDERLAND_THEME_REFRESH)
    else
        FireEvent(EventNames.ON_WONDERLAND_PAGE_CHANGE)
        if selGridChange then
            FireEvent(EventNames.ON_SEL_GRID_CHANGE)
        end
    end

end

function ModelWonderland:CheckSelGridEventChange(oldGrid,newGrid)
    if oldGrid and newGrid then
        local oldGridKey = oldGrid:GetGridKey()
        local newGridKey = newGrid:GetGridKey()
        if oldGridKey ~= newGridKey then
            return
        end

        local oldEventIdMap = {}
        local oldEventList = oldGrid:GetEventList()
        local oldCnt = #oldEventList
        local newEventList = newGrid:GetEventList()
        local newCnt = #newEventList
        if newCnt ~= oldCnt then
            return true
        end
        for k,v in ipairs(oldEventList) do
            oldEventIdMap[v.eventId] = true
        end

        for k,v in ipairs(newEventList) do
            if not oldEventIdMap[v.eventId] then
                return true
            end
        end
    end
end

function ModelWonderland:CheckShowEndBox()
    local isPass = self._passAwardState and self._passAwardState == 1
    if not isPass then
        return false
    end

    local eventData,eventInfo = self:GetTimeEvent()
    if eventInfo and not eventInfo.isEnter then
        return false
    end

    return true
end

