function ModelWonderland:OnWonderlandOpsResp(pb)
    local type = pb.type
    if type == ModelWonderland.EVENT_WORLD_LEAVES then
        if self._selectGrid then
            FireEvent(EventNames.ON_WONDERLAND_OPER_RET,type,self._selectGrid)
        end
    elseif self._waitRefreshEvent[type] then
        gLGpManager:FindWonderlandCopyGp():SetWaitEvent(type)
    elseif type == ModelWonderland.EVENT_SELECT_GRID then

        self:ReleaseReqProtect()

        local callback = self._selectCallBack
        self._selectCallBack = nil
        if callback then
            callback()
        end
    elseif type == ModelWonderland.EVENT_MIRROR or type == ModelWonderland.EVENT_SINGING or type == ModelWonderland.EVENT_ORGAN then
        if self._selectGrid then
            FireEvent(EventNames.ON_GAIN_ITEM,self._selectGrid,type)
        end
    end
end

function ModelWonderland:OnWonderlandQuestResp(pb)
    self._questData =
    {
        questId = pb.questId,
        schedule = pb.schedule,
        status = pb.status,
    }
end

function ModelWonderland:OnWonderlandHeroOpsResp(pb)


    if pb.syncType == 0 then
        self._heroList ={}
        for k,v in ipairs(pb.heroInfo) do
            local id = v.id
            self._heroList[id] = v
        end
    elseif pb.syncType == 2 then
        self._hpChangeHeros = {}
        for k,v in ipairs(pb.heroInfo) do
            local id = v.id
            local oldData = self._heroList[id]
            if oldData then
                oldData.curHp = v.curHp
            end
            self._hpChangeHeros[id] = true
        end

        FireEvent(EventNames.ON_WONDER_HERO_HP_CHANGE)
    else
        for k,v in ipairs(pb.heroInfo) do
            local id = v.id
            self._heroList[id] = v
        end
    end

end

