function ModelWonderland:GetHeroListInSpring()
    local list = {}
    for k,v in pairs(self._heroList) do
        if v.curHp>0 then
            table.insert(list,v)
        end

    end

    table.sort(list,function (a,b)
        if a.curHp ~= b.curHp then
            return a.curHp<b.curHp
        end

        return a.power>b.power
    end)
    return list
end

function ModelWonderland:GetHeroListInRevival()
    local list = {}
    for k,v in pairs(self._heroList) do
        table.insert(list,v)
    end

    table.sort(list,function (a,b)
        local aDead = a.curHp<=0 and 0 or 1
        local bDead = b.curHp<=0 and 0 or 1
        if aDead ~= bDead then
            return aDead<bDead
        end
        if a.curHp ~= b.curHp then
            return a.curHp<b.curHp
        end

        return a.power>b.power
    end)
    return list
end

function ModelWonderland:GetHeroListInReborn()
    local list = {}
    local select = nil
    for k,v in pairs(self._heroList) do
        table.insert(list,v)
        if not select then
            select = v
        else
            select = self:GetRebornPrio(select,v)
        end
    end

    table.sort(list,function (a,b)
        if a.power~= b.power then
            return a.power>b.power
        end

        local aDead = a.curHp<=0 and 0 or 1
        local bDead = b.curHp<=0 and 0 or 1
        if aDead ~= bDead then
            return aDead<bDead
        end


        return a.refId>b.refId
    end)
    return list,select
end

function ModelWonderland:GetRebornPrio(hero1,hero2)
    local aDead = hero1.curHp <= 0 and 1 or 2
    local bDead = hero2.curHp <= 0 and 1 or 2

    if aDead ~= bDead then
        return aDead< bDead and hero1 or hero2
    end

    local aFull = hero1.curHp < hero1.maxHp and 1 or 2
    local bFull = hero2.curHp < hero2.maxHp and 1 or 2

    if aFull ~= bFull then
        return aFull< bFull and hero1 or hero2
    end

    return hero1.power > hero2.power and hero1 or hero2
end

function ModelWonderland:GetWonderHeroList(noDead)
    local list = {}
    for k,v in pairs(self._heroList) do
        if noDead then
            if v.curHp>0 then
                table.insert(list,v)
            end
        else
            table.insert(list,v)
        end
    end
    return list
end

function ModelWonderland:GetHeroListInBattle()
    local list = {}
    for k,v in pairs(self._heroList) do
        table.insert(list,v)
    end

    table.sort(list,function (a,b)
        return a.power>b.power
    end)
    return list
end

function ModelWonderland:CheckHasHeroHurt()
    for k,v in pairs(self._heroList) do
        if v.curHp>0 and v.curHp<v.maxHp then
            return true
        end
    end
    return false
end

function ModelWonderland:CheckHasHeroDead()
    for k,v in pairs(self._heroList) do
        if v.curHp<=0 then
            return true
        end
    end
    return false
end


function ModelWonderland:GetEventReward(rewardId,floor)
    floor = floor or 0
    local level = gModelPlayer:GetPlayerLv()
    local floorList = self._rewardConfigs[rewardId]
    if not floorList then
        printErrorN(string.format("not wonder reward %s",rewardId))
        return {}
    end
    local list = floorList[floor]
    if not list then
        printInfoN(string.format("not wonder floor %s",floor))
        list = floorList[0]
    end
    if not list then
        printErrorN(string.format("not wonder reward %s",rewardId))
        return {}
    end
    for k,v in ipairs(list) do
        if level>= v.levelMin and level<= v.levelMax then
            return LxDataHelper.ParseItem(v.reward)
        end
    end
    return {}
end

