function ModelWonderland:GetItemNum(itemId)
    if not self._itemList then
        return 0
    end
    local data = self._itemList[itemId]
    if data then
        return data.itemNum
    end
    return 0
end

function ModelWonderland:GetEventTextId(eventId,index)
    local cfg = self:GetEventConfig(eventId)
    local choose = cfg.choose
    local tempStrs = string.split(choose,"|")

    if #tempStrs==0 then
        return
    end

    local index = index or 1
    local textId = tempStrs[index]
    return textId and tonumber(textId)

end

function ModelWonderland:GetDefaultEventText(textId)
    local cfg =  GameTable.DreamlandEventTxtRef[textId]
    if not cfg then
        return
    end

    local answer = cfg.answer
    answer = ccLngText(answer)
    local temp = string.split(answer,"|")
    local data =
    {
        desc = ccLngText(cfg.dec),
        answer=temp
    }
    return data
end

