function ModelWonderland:GetBookEventList(themeId)
    local list ={}
    for k,v in pairs(GameTable.WonderHelpRef) do
        local mapid = v.mapId
        if mapid == 0 or mapid == themeId then
            table.insert(list,v)
        end
    end

    table.sort(list,function (a,b)
        local aMapId = a.mapId
        local bMapId = b.mapId
        if aMapId~= bMapId then
            return aMapId>bMapId
        end
        return a.refId <b.refId end)
    return list
end

function ModelWonderland:GetTreasureList()
    local list ={}
    for k,v in pairs(GameTable.DreamlandBuffRef) do
        local type = v.type
        if type ~= 0 and type ~= 4 then
            table.insert(list,v)
        end
    end

    table.sort(list,function (a,b)
        local aQua = a.quality
        local bQua = b.quality
        if aQua ~= bQua then
            return aQua>bQua
        end

        local aType = a.type
        local bType = b.type
        if aType~=bType then
            return aType>bType
        end

        local aId = a.refId
        local bId = b.refId
        return aId<bId
    end)

    return list
end

