function ModelWonderland:GetHeroListOnTs()
    local formation = gModelFormation:GetFormation(LCombatTypeConst.COMBAT_WONDERLAND)
    local formationHeros ={}
    if formation then
        for k,v in ipairs(formation.grids) do
            local id = v.id
            formationHeros[id] = true
        end
    end

    local list = {}
    for k,v in pairs(self._heroList) do
        if v.curHp>0 then
            table.insert(list,v)
        end

    end

    table.sort(list,function (a,b)
        local aPrio = formationHeros[a.id] and 0 or 1
        local bPrio = formationHeros[b.id] and 0 or 1
        if aPrio~= bPrio then
            return aPrio<bPrio
        end
        if a.power~= b.power then
            return a.power>b.power
        end

        return a.refId<b.refId

    end)
    return list

end

