function ModelWonderland:GetMonsterEventReward(eventId)
    local cfg = self:GetEventConfig(eventId)
    if not cfg then
        return
    end
    local reward = self:GetEventRewardId(eventId)
    local random = cfg.random
    local key,value = LxDataHelper.ParseIntKV_Equal(random)
    local ratio = value
    return reward,ratio
end

--- 生效，品质，等级，id
function ModelWonderland:GetSortedTreasureList()
    local formation = gModelFormation:GetFormation(LCombatTypeConst.COMBAT_WONDERLAND)
    local refIdList = {}
    local raceList = {}
    local careerList={}
    if formation then
        for k,v in ipairs(formation.grids) do
            local id = v.id
            local heroData = self:GetHeroData(id)
            local refId =nil
            if heroData then
                refId = heroData.refId
                refIdList[refId] = true
                local race = gModelHero:GetHeroRace(refId)
                raceList[race] = true
                local career = gModelHero:GetHeroCareerType(refId)
                careerList[career] = true
            end
        end
    end

    local dataListForSort={}
    for k,v in pairs(self._treasureList) do
        local data ={}
        data.refId = k
        local isOn = self:IsTreasureOn(k,refIdList,raceList,careerList)
        data.activePrio = isOn and 1 or 2
        local cfg = GameTable.DreamlandBuffRef[k]
        data.quality = cfg.quality
        data.level = cfg.lv
        table.insert(dataListForSort,data)
    end

    table.sort(dataListForSort,function (a,b)
        if a.activePrio~= b.activePrio then
            return a.activePrio<b.activePrio
        end
        if a.quality~= b.quality then
            return a.quality>b.quality
        end
        if a.level ~= b.level then
            return a.level>b.level
        end
        return a.refId <b.refId
    end)

    return dataListForSort

end

---加成是否生效
function ModelWonderland:IsTreasureOn(treasureId,refIdList,raceList,careerList)
    local rangeList = self._buffRangeConfigs[treasureId]
    if not rangeList then
        return false
    end


    for k,v in ipairs(rangeList) do
        local type = v.type
        local para = v.para
        local isOn = false
        if type == -1 then
            isOn = true
        elseif type == 1 then
            if para then
                isOn = refIdList[para] or false
            end
        elseif type == 2 then
            if para then
                isOn = careerList[para] or false
            end
        elseif type == 3 then
            if para then
                isOn = raceList[para] or false
            end
        end

        if isOn then
            return isOn
        end
    end

    return false
end

