function ModelWonderland:FormatBattleData(pb,eventName,eventId,bossType)

    local battledata = {}
    battledata.formationRefId = pb.formationRefId

    local bossList= {}
    local isMonster = false
    for k,v in ipairs(pb.heroInfo) do
        local data =
        {
            refId = v.refId,
            id = v.id,
            heroType = v.heroType,
            lvl = v.lvl,
            star = v.star,
            maxHp = v.maxHp,
            curHp = v.curHp,
            power = v.power,
            grade = v.grade,
            monsterAddCost = pb.monsterAddCost,
            skin = v.skin,
            form = v.form,
        }

        if v.heroType == ModelWonderland.ENEMY_MONSTER then
            isMonster = true
        end

        table.insert(bossList,data)
    end

    battledata.bossList  = bossList

    local grids = {}
    for k,v in ipairs(pb.grids) do
        local data =
        {
            id = v.id,
            grid = v.grid,
        }
        table.insert(grids,data)
    end

    local treasureIds = nil

    if pb.treasureSkilIds then
        treasureIds = {}
        local index = 1
        for k,v in ipairs(pb.treasureSkilIds) do
            if v>0 then
                local data =
                {
                    index = index,
                    skillId = v,
                }
                treasureIds[index] =data
            end
            index = index + 1
        end
    end


    battledata.grids = grids
    battledata.otherName = eventName
    battledata.power = pb.power
    battledata.eventName = eventName
    battledata.treasureIds = treasureIds
    battledata.eventRefId = eventId
    battledata.bossType = bossType or 1 --1,普通怪，血量限制 2,时光领主 ，无限制
    battledata.monsterAddCost = pb.monsterAddCost
    return battledata
end

