function ModelWonderland:CanTreasureLvUp(refId)
    local curCfg = GameTable.DreamlandBuffRef[refId]
    if not curCfg then
        printErrorN(string.format("not wonderbuff refId %s ",refId))
        return false,refId,1
    end
    local group = curCfg.group
    local defaultLv = curCfg.lv
    for k,v in pairs(self._treasureList) do
        local treasureId = v.itemId
        local ownCfg = GameTable.DreamlandBuffRef[treasureId]
        local curGroup = ownCfg.group
        local curLv = ownCfg.lv
        if curGroup == group then
            local nextId = ownCfg.nextLv
            if nextId > 0 then
                return true,nextId,curLv
            end
        end
    end
    return false,refId,defaultLv
end

