function ModelWonderland:GetFormationPower(heroIdList)
    --同组取等级最高的宝物
    local groupList = {}
    for k,v in pairs(self._treasureList) do
        local treasureId = k
        local cfg = self:GetTreasureConfig(treasureId)
        local group = cfg.group
        local lv = cfg.lv
        local list = groupList[group]
        if not list then
            list = {}
            groupList[group] = list
        end
        local data =
        {
            treasureId = treasureId,
            lv = lv
        }

        table.insert(list,data)
    end

    local treasureList ={}
    for k,v in pairs(groupList) do
        table.sort(v,function (a,b)
            return a.lv>b.lv
        end)

        local first = v[1]
        table.insert(treasureList,first)
    end

    --计算每个英雄生效系数


    local totalPower = 0
    local defaultPower = 0

    local percent = 0
    --local positiveTreas = {}
    for k,v in pairs(heroIdList) do
        local heroData = self:GetHeroData(v)
        if heroData then
            local refId = heroData.refId
            local totalFight = 0
            for k1,v1 in pairs(treasureList) do
                local treasureId = v1.treasureId
                local isPositive = self:IsTreasurePositive(refId,treasureId)
                if isPositive then
                    local cfg = self:GetTreasureConfig(treasureId)
                    local fight = cfg.fight
                    totalFight = fight + totalFight

                    --if not positiveTreas[v1] then
                    --    positiveTreas[v1] = true
                        --percent = percent+ fight
                    --end
                end
            end

            local power =math.floor(heroData.power*(1+ totalFight))
            totalPower = totalPower + power
            defaultPower = defaultPower+ heroData.power
        end
    end

    if defaultPower>0 then
        percent = totalPower/defaultPower -1
    end


    return totalPower,percent
end

function ModelWonderland:IsTreasurePositive(refId,treasureId)
    local rangeList = self._buffRangeConfigs[treasureId]
    if not rangeList then
        return false
    end
    local race = gModelHero:GetHeroRace(refId)
    local career = gModelHero:GetHeroCareerType(refId)

    for k,v in ipairs(rangeList) do
        local type = v.type
        local para = v.para
        local isOn = false
        if type == -1 then
            isOn = true
        elseif type == 1 then
            isOn = refId == para
        elseif type == 2 then
            isOn = career == para
        elseif type == 3 then
            isOn = race == para
        end

        if isOn then
            return true
        end
    end


    return false
end

