function ModelWonderland:IsBossTrigger(themeId)
    local itemId,itemNum = self:GetBossTriggerCondition(themeId)
    if not itemId or not itemNum then
       return false
    end
    local ownNum = self:GetItemNum(itemId)
    if ownNum>=itemNum then
        return true
    end
end

function ModelWonderland:GetBossTriggerCondition(themeId)
    local themeCfg = self:GetThemeConfig(themeId)
    local endEvent = themeCfg.endEvent
    local eventCfg = self:GetEventConfig(endEvent)
    local parameter = eventCfg.parameter
    local tempStrs = string.split(parameter,"|")
    if #tempStrs<1 then
        return
    end
    local strs= string.split(tempStrs[1],"=")
    if #strs<2 then
        return
    end
    local itemId = tonumber(strs[1])
    local itemNum = tonumber(strs[2])
    return itemId,itemNum
end



