---配置预处理
function ModelWonderland:ParseConfig()
    local rewardConfigs = {}
    for k,v in pairs(GameTable.DreamlandRewardRef) do
        local rewardGroup = v.rewardGroup
        local reward = v.reward
        local data =
        {
            levelMin = v.levelMin,
            levelMax = v.levelMax,
            reward = reward,
        }
        local list = rewardConfigs[rewardGroup]
        if not list then
            list ={}
            rewardConfigs[rewardGroup] = list
        end
        local floor = v.floor
        local tempList = list[floor]
        if not tempList then
            tempList = {}
            list[floor] = tempList
        end
        table.insert(tempList,data)

    end

    self._rewardConfigs = rewardConfigs

    local goodsConfig = {}
    for k,v in pairs(GameTable.DreamlandGoodsRef) do
        local reward = LxDataHelper.ParseItem_3(v.reward)
        local price = LxDataHelper.ParseItem_3(v.price)
        local discount = v.fixDiscount
        local data=
        {
            reward = reward,
            price = price,
            discount = discount,
        }
        goodsConfig[k] = data
    end

    self._goodsConfig = goodsConfig

    local independentEvents = {}
    local refreshEffList ={}
    --local gridIconList ={}
    local sceneEvents ={}
    local specialEvents = {}
    --local gridStateResList = {}

    local WonderThemeRef = self:GetModelConfig(ModelWonderland.DreamlandThemeRef)
    for k,v in pairs(WonderThemeRef) do
        local themeId = v.refId
        local ownEvent = v.ownEvent
        local tempStrs = string.split(ownEvent,";")
        for k1,v1 in ipairs(tempStrs) do
            local temp = string.split(v1,"=")
            if #temp> 0 then
                local eventId = tonumber(temp[1])
                independentEvents[eventId] = true
            end
        end
        local endEvent = v.endEvent
        independentEvents[endEvent] = true

        local difEvent = v.difficultyEvent
        if not string.isempty(difEvent) then
            local tempStrs = string.split(difEvent,";")
            for k1,v1 in ipairs(tempStrs) do
                local temp = string.split(v1,"=")
                if #temp> 0 then
                    local eventId = tonumber(temp[1])
                    independentEvents[eventId] = true
                end
            end
        end

        local sceneEvent = v.sceneEvent
        if not string.isempty(sceneEvent) then
            local type,eventId = LxDataHelper.ParseIntKV_Equal(sceneEvent)
            local data =
            {
                type = type,
                eventId = eventId,
            }
            sceneEvents[themeId] = data
        end

        local refreshEff = v.refreshEffect
        local strs = string.split(refreshEff,",")
        if #strs>=3 then
            local effList = {
                outAni = strs[1],
                inAni = strs[2],
                adAni = strs[3],

            }
            refreshEffList[k] = effList
        end

        local typeList = LxDataHelper.ParseNumber_Sign(tostring(v.specialEvent))
        local typeMap = {}
        for k1,v1 in ipairs(typeList) do
            typeMap[v1] = true
        end

        specialEvents[k] = typeMap

        --strs = string.split(v.platformEffect,',')
        --gridStateResList[k] = strs
    end

    self._independentEvents = independentEvents
    --self._gridIconList = gridIconList
    self._sceneEvents = sceneEvents
    self._refreshEffList = refreshEffList
    self._specialEvents = specialEvents
    --self._gridStateEffList = gridStateResList

    self._buffRangeConfigs ={}
    local buffGroupList ={}
    for k,v in pairs(GameTable.DreamlandBuffRef) do
        local range = v.range
        local rangeList = {}

        if string.isempty(range) then
            local rangeT ={
                type = -1
            }
            table.insert(rangeList,rangeT)
        else
            local tempStr = string.split(range,"|")
            for k1,v1 in ipairs(tempStr) do
                local rangeT = {}
                local type,para = LxDataHelper.ParseIntKV_Equal(v1)
                rangeT.type = type
                rangeT.para = para
                table.insert(rangeList,rangeT)
            end

        end

        local group = v.group
        local list = buffGroupList[group]
        if not list then
            list = {}
            buffGroupList[group] = list
        end

        table.insert(list,v)

        self._buffRangeConfigs[k] = rangeList
    end

    self._buffGroupList = buffGroupList

    local eventMonsterList = {}
    local WonderEventRef = self:GetModelConfig(ModelWonderland.DreamlandEventRef)
    for k,v in pairs(WonderEventRef) do
        local monsterType = v.monsterType
        local nums = LxDataHelper.ParseNumber_Sign(monsterType,"=")
        if #nums>=3 then
            local type = tonumber(nums[2])
            eventMonsterList[k] = type
        end
    end

    self._eventMonsterList = eventMonsterList

    local hintMap = {}
    for k,v in pairs(GameTable.DreamlandHintRef) do
        local eventList = LxDataHelper.ParseNumber_Sign(v.event,";")
        for k1,v1 in ipairs(eventList) do
            hintMap[v1] = v
        end
    end

    self._hintMap = hintMap
end

function ModelWonderland:RecordOldState()
    if self._gridStateRecords then
        return
    end

    self._gridStateRecords = self:CreateStateRecord()
end


function ModelWonderland:GetGridOldState()
    if not self._gridStateRecords then
        self._gridStateRecords = self:CreateStateRecord()
    end
    return self._gridStateRecords
end

function ModelWonderland:CreateStateRecord()
    local gridStateRecords ={}

    for k,v in pairs(self._layerList) do
        for k1,v1 in pairs(v.grids) do
            local layerIndex = v1:GetLayerIndex()
            local gridIndex = v1:GetGridIndex()
            local gridKey = self:FormatGridKey(layerIndex,gridIndex)

            local state = v1:GetStatus()
            local isEnd = self:GetCurLayer() == 20
            local themeType = self:GetThemeType()
            if themeType == 4 and not isEnd then
                if state == StructWonderlandGrid.DISAPPEAR or state == StructWonderlandGrid.PASSED then
                    state = StructWonderlandGrid.FORBIDDEN
                end
            end

            gridStateRecords[gridKey] = state
        end
    end
    return gridStateRecords
end

function ModelWonderland:ClearOldRecord()

    self._gridStateRecords = nil
end

function ModelWonderland:CheckRelativeEvents(list)
    local exist = {}
    local curLayer = self:GetCurLayer()
    for k,v in pairs(self._layerInfos) do
        if k >curLayer then
            local grids = v.grids
            for k1,v1 in pairs(grids) do
                local eventList = v1:GetEventList()
                for k2,v2 in pairs(eventList) do
                    local eventCfg = self:GetEventConfig(v2.eventId)
                    local type = eventCfg.type
                    local data = list[type]
                    if data then
                        exist[data.index] = type
                    end

                end
            end
        end
    end
    return exist
end

function ModelWonderland:GetLayerGridCnt(layerIndex)
    if not self._layerInfos then
        return 1
    end
    local layer = self._layerInfos[layerIndex]
    if not layer then
        return 1
    end

    return #(layer.grids)
end

