function ModelWonderland:GetCurFormationPower()
    local formation = gModelFormation:GetFormation(LCombatTypeConst.COMBAT_WONDERLAND)
    local idList ={}
    if formation and formation.grids then
        for k,v in ipairs(formation.grids) do
            local id = v.id
            table.insert(idList,id)
        end
    end
    if #idList ==0 then
        return 0
    end

    return self:GetFormationPower(idList)
end

