    for k, v in ipairs(eventList) do
        if eventId == v.eventId then
            return v
        end
    end
end

function ModelWonderland:IsSpecialEvent(eventType)
    local themeId = self:GetThemeId()
    if not themeId then
        return
    end
    if not self._specialEvents then
        return
    end
    local typeMap = self._specialEvents[themeId]
    return typeMap and typeMap[eventType]
end


function ModelWonderland:GetFreeRebornCnt()
    return self._freeRebornCnt or 0
end

function ModelWonderland:HasAffectEventType(gridKey,eventType)
    local has = false
    local affectList = gModelWonderland:GetAffectByGrid(gridKey)
    if affectList then
        for k,v in ipairs(affectList) do
            local affCfg = gModelWonderland:GetEventConfig(v)
            local type = affCfg.type
            if type == eventType then
                has = true
                break
            end
        end
    end

    return has
end

function ModelWonderland:GetPlatformEffectName(oldState,newState)
    if oldState == newState then
        return
    end

    local themeId  = self:GetThemeId()
    local effResList = self:GetConfigValueImpl(ModelWonderland.DreamlandThemeRef,themeId,"platformEffect",function (value) return string.split(value,',') end)
    if not effResList then
        return
    end

    local type = nil
    local effRes = nil
    local isOldUp = self._gridUpStates[oldState]
    local isNewUp = self._gridUpStates[newState]
    if not isOldUp and isNewUp then
        effRes = effResList[1]
        type = 0
    end
    if newState == StructWonderlandGrid.PASSED then
        effRes = effResList[2]
        type = 1
    elseif newState == StructWonderlandGrid.DISAPPEAR then
        effRes = effResList[3]
        type = 1
    end
    return effRes,type
end

function ModelWonderland:IsEventShow(layerIndex,gridIndex,eventId)
    local eventCfg = self:GetEventConfig(eventId)
    local eventType = eventCfg.type
    if self:IsMapEnd() then
        if eventType== ModelWonderland.EVENT_TIME then
            return true
        end

        return false
    end
    local eventCfg = self:GetEventConfig(eventId)
    local roleLayer = self:GetCurLayer()
    local gridKey = self:FormatGridKey(layerIndex,gridIndex)

    local gridData = self:GetGridDataByGridKey(gridKey)
    local status = gridData:GetStatus()
    local eventType = eventCfg.type
    local showEvent = true

    if status == StructWonderlandGrid.DISAPPEAR then
        if eventType ~= ModelWonderland.EVENT_BEAN_VINE then
            showEvent = false
        end
    end

    local themeType = gModelWonderland:GetThemeType()

    if themeType == 4 then
        if layerIndex<= roleLayer then
            if eventType ~= ModelWonderland.EVENT_BEAN_VINE then
                showEvent = false
            end
        end
    elseif themeType== 2 then
        local hasSnow  = self:HasAffectEventType(gridKey,ModelWonderland.EVENT_SNOW)
        local isIndependent = self:IsIndependentEvent(eventId)
        if not isIndependent and hasSnow  then
            if layerIndex- roleLayer>1 then
                showEvent = false
            end
        end
    elseif themeType == 5 then
        if eventType == ModelWonderland.EVENT_BEAST then
            showEvent = false
        elseif eventType == ModelWonderland.EVENT_OCTOPUS then
            if status == StructWonderlandGrid.PASSED then
                showEvent = true
            end
        end
    elseif themeType == 1 then
        if eventType == ModelWonderland.EVENT_GRANDMA  then
            if status == StructWonderlandGrid.PASSED then
                showEvent = false
            end
        end
    end

    local hideType = eventCfg.hideType

    if hideType == 1 then
        if layerIndex-roleLayer>2 then
            showEvent = false
        end
    end

    return showEvent
end

function ModelWonderland:IsInScopes(gridKey,eventId)
    local gridData = gModelWonderland:GetGridDataByGridKey(gridKey)
    local curLayer = gModelWonderland:GetCurLayer()
    local curGrid = gModelWonderland:GetCurGrid()
    for k,v in ipairs(gridData:GetEventList()) do
        if v.eventId == eventId then
            for k1,v1 in ipairs(v.scopes) do
                if curLayer == v1.tierIndex and curGrid == v1.gridIndex then
                    return true

                end
            end
        end
    end

    return false
end


function ModelWonderland:GetBeastEventInfo()
    if string.isempty(self._themeMoreInfo) or self:IsMapEnd() then
        return false,-1
    end
    local strs =LxDataHelper.ParseNumber_Sign(self._themeMoreInfo,"|") --string.split(self._themeMoreInfo,"|")
    local isMeet = false
    local layerIndex = 0
    local gridIndex = 0
    if #strs == 3 then
        layerIndex = tonumber(strs[1])
        gridIndex = tonumber(strs[2])
        isMeet = tonumber(strs[3]) == 1
    end

    return isMeet,layerIndex,gridIndex
end

function ModelWonderland:GetBeastEvent()
    local isMeet,layerIndex,gridIndex = self:GetBeastEventInfo()
    if layerIndex ==-1 then
        return
    end

    local data = self._beastEventData
    if not data then
        data =
        {
            eventId = 50008,
            layerIndex =layerIndex,
            gridIndex = gridIndex,
            isMeet = isMeet
        }
        self._beastEventData = data
    end

    data.layerIndex = layerIndex
    data.gridIndex = gridIndex
    data.isMeet = isMeet

    return data
end
function ModelWonderland:IsMapEnd()
    return self._passAwardState and self._passAwardState>=1
end

function ModelWonderland:GetBeastSleep()
    if not self._beastEvent then
        return 0
    end

    local moreInfo = self._beastEvent.moreInfo
    local bout = tonumber(moreInfo) or 0
    return bout

end

function ModelWonderland:OnReceiveEffect(effdata)
    if not self._effectMap then
        self._effectMap = {}
    end

    self._effectMap[effdata.eventType] = effdata
end

function ModelWonderland:DeleteEffect(eventType)
    if self._effectMap then
        self._effectMap[eventType] = nil
    end
end

function ModelWonderland:ClearAllEffect()
    self._effectMap = nil
end

function ModelWonderland:CheckShowHud(eventType)
    local data =self._effectMap and self._effectMap[eventType]
    if data then
        self._effectMap[eventType] = nil
        FireEvent(EventNames.ON_SHOW_WONDER_HUD,data)

        printInfoN("show hud type "..tostring(eventType))
    end
end

function ModelWonderland:GetHintData(eventType)
    return self._hintMap[eventType]
end

function ModelWonderland:SetSkipPrepare(isSkip)
    if isSkip then
        local canSkip = gModelBattle:CanSkip(LCombatTypeConst.COMBAT_WONDERLAND,true)
        if not canSkip then
            return
        end
    end

    local value = isSkip and 1 or 0
    LPlayerPrefs.SetWonderSkipB(value)
    return true
end

function ModelWonderland:GetSkipPrepare()
    local value = tonumber(LPlayerPrefs.wonderSkipB) or 0
    return value == 1
end


function ModelWonderland:GetFormationHeroCnt(noLimit)
    local formation = gModelFormation:GetFormation(LCombatTypeConst.COMBAT_WONDERLAND)
    local cnt = 0
    local grids = {}
    if formation and formation.grids then
        for k,v in ipairs(formation.grids) do
            local id = v.id
            local heroData = self:GetHeroData(id)

            if heroData then
                if noLimit or heroData.curHp>0 then
                    cnt = cnt + 1
                    table.insert(grids,v)
                end
            end
        end
    end
    return cnt,grids
end

function ModelWonderland:EnterBattle(battleData,curWnd)

    if table.isempty(self._heroList) then
        printErrorN("no wonderland hero info")
        return
    end

    local isSkip = self:GetSkipPrepare()
    if isSkip then
        local isTimeLord = battleData.isTimeLord
        local heroCnt,newGrids  = self:GetFormationHeroCnt(isTimeLord)

        local func = function()

            GF.CloseWndByName(curWnd)

            local combatData =
            {
                combatType = LCombatTypeConst.COMBAT_WONDERLAND,
                skipBattle = true,
                eventRefId = battleData.eventRefId,
            }
            gModelBattle:OnCombatReq(combatData)

        end

        local leftFunc = function()
            gLFightManager:PrepareGoToBattle(LCombatTypeConst.COMBAT_WONDERLAND,battleData)

        end
        if heroCnt==0 then
            gModelGeneral:OpenUIOrdinTips({refId = 70012,func = leftFunc })
            return
        elseif heroCnt <5 then
            gModelGeneral:OpenUIOrdinTips({refId = 70011,func = func,leftFunc = leftFunc })
            return
        end

        func()

    else
        gLFightManager:PrepareGoToBattle(LCombatTypeConst.COMBAT_WONDERLAND,battleData)
    end
end


function ModelWonderland:GetGridIconPath(themeId,state)
    local iconPathList = self:GetConfigValueImpl(ModelWonderland.DreamlandThemeRef,themeId,"platform",function (value)
        return string.split(value,',')
    end)

    local index = nil
    if state == StructWonderlandGrid.PASSED then
        index = 2
    elseif state == StructWonderlandGrid.ALLOW or state == StructWonderlandGrid.SELECTED
            or state == StructWonderlandGrid.PLAYER then
        index = 1
    else
        index = 3
    end

    return iconPathList[index]
end

function ModelWonderland:GetCardShow(eventId)
    local eventCfg = self:GetEventConfig(eventId)
    local exchange = eventCfg.exchange
    local paras = string.split(exchange,'=')
    local exchangeId = tonumber(paras[2])
    if not exchangeId then
        printErrorN("not exchange")
        return
    end

    local exchangeCfg = self:GetEventConfig(exchangeId)
    local cardList = LxDataHelper.ParseNumber_Sign(exchangeCfg.parameter,'=')
    return cardList
end

function ModelWonderland:GetEventRewardId(eventId)
    local parseFunc = function(value)
        local strs = string.split(value,'|')
        local dataList = {}
        for k,v in ipairs(strs) do
            local temps = string.split(v,'=')
            local mode = tonumber(temps[1])
            local rewardId = tonumber(temps[2])
            dataList[mode] = rewardId
        end
        return dataList
    end
    local rewardList = self:GetConfigValueImpl(ModelWonderland.DreamlandEventRef,eventId,"reward",parseFunc)

    local curPattern = self:GetCurPattern()
    return rewardList[curPattern]
end

function ModelWonderland:GetTaskRewardId(taskId)
    local parseFunc = function(value)
        local strs = string.split(value,'|')
        local dataList = {}
        for k,v in ipairs(strs) do
            local temps = string.split(v,'=')
            local mode = tonumber(temps[1])
            local rewardId = tonumber(temps[2])
            dataList[mode] = rewardId
        end
        return dataList
    end
    local rewardList = self:GetConfigValueImpl(ModelWonderland.WonderTaskRef,taskId,"reward",parseFunc)

    local curPattern = self:GetCurPattern()
    return rewardList[curPattern]
end

function ModelWonderland:CheckSelectPattern(pattern)
    local maxPass = self._viaPatternType or 0
    local pass = maxPass>= pattern - 1
    return pass
end

function ModelWonderland:GetTimeLordShow(eventId)
    local ref = self:GetEventConfig(eventId)
    if not ref then
        printErrorN(string.format("not event ref %s",eventId))
        return
    end

    local param = ref.parameter
    local eventList = {}
    local strs = string.split(param,'=')
    for k= 2,4 do
        local monsterId = tonumber(strs[k])
        table.insert(eventList,monsterId)
    end
    return eventList
end

function ModelWonderland:GetDifIconList()
    local parseFun = function(value)
        return string.split(value,'=')
    end
    local iconPathList = self:GetParaConfigValueImpl(ModelWonderland.DreamlandConfigRef,"difficultyIcon",parseFun)
    return iconPathList
end

function ModelWonderland:EnterWonderMap()
    if self._isInMap then
        local eventData,eventInfo = self:GetTimeEvent()
        if eventInfo and eventInfo.isEnter then
            GF.ChangeMap("LWonderlordMap",false,{data = eventData})
        else
            GF.ChangeMap("LWonderlandMap")
        end
    else
        GF.ChangeMap("LCityMap")
    end
end

function ModelWonderland:CheckChangeMap()
    if not self._isInMap then
        return
    end
    local curMap = GF.GetCurMap()

    local eventData,eventInfo = self:GetTimeEvent()
    if eventInfo and eventInfo.isEnter then
        if not curMap:IsSameMap("LWonderlordMap") then
            GF.ChangeMap("LWonderlordMap",false,{data = eventData})
        end
    else
        if not curMap:IsSameMap("LWonderlandMap") then
            GF.ChangeMap("LWonderlandMap")
        end
    end
end

