function ModelWonderland:ParseTimeEventInfo(moreInfo)
    local strs = string.split(moreInfo,'=')
    local isEnter = strs[1] == '1'
    local idMap = {}
    if strs[2] then
        local idList = LxDataHelper.ParseNumber_Sign(strs[2],'|')
        for k,v in ipairs(idList) do
            idMap[v] = true
        end
    end

    return {isEnter = isEnter,idMap = idMap}
end

function ModelWonderland:GetTimeEvent()
    local eventData = nil
    local curLayer = self:GetCurLayer()
    for k,v in pairs(self._layerInfos) do
        if k >curLayer then
            local grids = v.grids
            for k1,v1 in pairs(grids) do
                local eventList = v1:GetEventList()
                for k2,v2 in pairs(eventList) do
                    local eventCfg = self:GetEventConfig(v2.eventId)
                    if eventCfg then
                        local type = eventCfg.type
                        if type == ModelWonderland.EVENT_TIME then
                            eventData =
                            {
                                eventId = v2.eventId,
                                canSelect = true,
                                layerIndex = k,
                                gridIndex = v1:GetGridIndex(),
                                state = v1:GetStatus(),
                                moreInfo = v2.moreInfo,
                            }
                        end
                    else
                        printErrorN(string.format("no event cfg refId %s",v2.eventId))
                    end

                end
            end
        end
    end

    local eventInfo = nil
    if eventData then
        eventInfo = self:ParseTimeEventInfo(eventData.moreInfo)
    end

    return eventData,eventInfo
end

function ModelWonderland:IsTimeLordFinish(eventId)
    local timeEvent,eventInfo = self:GetTimeEvent()

    if eventInfo and eventInfo.idMap[eventId] then
        return true
    end

    return false
end

function ModelWonderland:GetRefreshCost(key,index)
    local parseFunc = function(value)
        return LxDataHelper.ParseItem_3List(value,';')
    end

    local costList = self:GetParaConfigValueImpl(ModelWonderland.DreamlandConfigRef,key,parseFunc)

    return costList[index]

end

function ModelWonderland:RefreshFormation(data)
    local layerIndex = data.layerIndex
    local gridIndex = data.gridIndex
    local eventId = data.eventId
    local moreInfo = string.format("%s|%s",layerIndex,gridIndex)

    if data.eventType == ModelWonderland.EVENT_TIME_LORD then
        return
    end
    local refreshFunc = function()
        self:WonderlandOpsReq(ModelWonderland.EVENT_REFRESH_MONSTER,moreInfo)
        self:WonderlandHeroMonsterReq(1,layerIndex,gridIndex,eventId)
    end

    local refreshMax = self:GetWonderlandPara("refreshNum")
    local refreshCnt = data.refreshCnt

    local curIndex= refreshMax - refreshCnt + 1

    local cost = self:GetRefreshCost("originRefreshExpend",curIndex)
    if cost then
        local itemNum = cost.itemNum
        if itemNum == 0 then
            refreshFunc()
        else
            local para =
            {
                refId = 70014,
                func = refreshFunc,
                para = {itemNum},
                consume = itemNum,
            }

            gModelGeneral:OpenUIOrdinTips(para)
        end
    end
end

function ModelWonderland:GetLordEffect()
    local parseFunc = function(value)
        return string.split(value,";")
    end

    local effList = self:GetParaConfigValueImpl(ModelWonderland.DreamlandConfigRef,'bossEffect',parseFunc)

    return effList
end

function ModelWonderland:IsBuffActivate(index)
    local key = "abyssActivate"..index
    local activeLayer = self:GetWonderlandPara(key)
    if self._maxLayerIndex >= activeLayer then
        return true
    end

    return false,activeLayer
end

function ModelWonderland:GetEventData(layerIndex,gridIndex,eventId)
    local grid = self:GetGridData(layerIndex,gridIndex)
    for k,v in ipairs(grid:GetEventList()) do
        if v.eventId == eventId then
            return v
        end
    end
end

function ModelWonderland:GetBgByPattern(pattern)
    local ref = self:GetModelConfig(ModelWonderland.DreamlandThemeRef)
    for k,v in pairs(ref) do
        if v.pattern == pattern then
            return v.auraIcon
        end
    end
end

function ModelWonderland:GetTreasureGroup(refId)
    local cfg = self:GetTreasureConfig(refId)
    if not cfg then
        return {}
    end
    local groupId = cfg.group
    local group = self._buffGroupList[groupId]

    if not group then
        return {}
    end

    table.sort(group,function (a,b)
        return a.lv<b.lv
    end)
    return group
end

function ModelWonderland:OnClickEntrance()
    local isInMap = self:IsInMap()
    if isInMap then
        local isFight = gLFightManager:IsCombatTypeInFight(LCombatTypeConst.COMBAT_WONDERLAND)
        if isFight then
            gLFightManager:PrepareGoToBattle(LCombatTypeConst.COMBAT_WONDERLAND)
            return
        end
        GF.OpenWndBottom("UIEden")
        self:EnterWonderMap()
    else
        GF.OpenWndBottom("UIEdenFront")
    end
end

