--清理工作
--停止计时器之类的
function ModelWonderland:OnModelClear()
    self._heroList={}
    self._treasureList={}
    self._hasFormation = false
end

function ModelWonderland:FormatWonderName(refId)
    local ref = self:GetThemeConfig(refId)
    local pattern = ref.pattern
    local patternName = nil
    if pattern == ModelWonderland.NORMAL then
        patternName = ccClientText(16793)
    elseif pattern == ModelWonderland.HARD then
        patternName = ccClientText(16794)
    else
        patternName = ccClientText(16795)
    end
    local name = string.format("%s[%s]",ccLngText(ref.name),patternName)
    return name
end

function ModelWonderland:AddReqProtect()
    self._reqTime = GetTimestamp()
end

function ModelWonderland:ReleaseReqProtect()
    self._reqTime = nil
end

function ModelWonderland:IsProtect()
    if not self._reqTime then
        return false
    end
    local timeLast = GetTimestamp() - self._reqTime
    if timeLast > 1 then
        return false
    end

    return true
end

function ModelWonderland:GetThemeByType(type,pattern)
    local ref = self:GetModelConfig(ModelWonderland.DreamlandThemeRef)
    for k,v in pairs(ref) do
        if v.type == type and v.pattern == pattern then
            return v
        end
    end
end

function ModelWonderland:CheckCanEnterType(themeType,showTip)
    if themeType > self._maxThemeType then
        if showTip then
            local themeCfg = self:GetThemeByType(self._maxThemeType,1)
            local format = ccLngText(self:GetWonderlandPara("themeOpenTips"))
            local str = string.replace(format,ccLngText(themeCfg.name))
            GF.ShowMessage(str)
        end

        return false
    end

    return true
end

function ModelWonderland:GetMaxThemeType()
    return self._maxThemeType or 1
end

function ModelWonderland:NotAllowRefreshType(eventType)
    if not self._notAllowMap then
        self._notAllowMap =
        {
            [ModelWonderland.EVENT_DEVIL] = true,
            [ModelWonderland.EVENT_QUEEN] = true,
            [ModelWonderland.EVENT_BOX_SELECT] = true,
            [ModelWonderland.EVENT_SPRITE] = true,
            [ModelWonderland.EVENT_WITCH] = true,
            [ModelWonderland.EVENT_TIME_LORD] = true,
        }
    end

    return self._notAllowMap[eventType]
end

function ModelWonderland:GetMaxUnlockPattern()
    local pattern = ModelWonderland.NORMAL
    if gModelFunctionOpen:CheckIsOpened(ModelFunctionOpen.WONDER_HARD) then
        pattern = ModelWonderland.HARD
    end
    if gModelFunctionOpen:CheckIsOpened(ModelFunctionOpen.WONDER_TOUGH) then
        pattern = ModelWonderland.TOUGH
    end
    return pattern
end

function ModelWonderland:GetEventInfoByType(eventType)
    local eventInfoMap = self._eventInfoByType
    if not eventInfoMap then
        eventInfoMap = {}
        self._eventInfoByType = eventInfoMap
    end

    local eventInfo = eventInfoMap[eventType]
    if eventInfo then
        return eventInfo
    end
    local WonderEventRef = self:GetModelConfig(ModelWonderland.DreamlandEventRef)
    for k,v in pairs(WonderEventRef) do
        eventInfoMap[v.type] = v
    end

    return eventInfoMap[eventType]
end

function ModelWonderland:IsEvilAwakeTimeChange()
    local oldTimes = self._oldAwakeTimes or 0
    local newTimes = self:GetItemNum(200005)
    if oldTimes ~= newTimes then
        self._oldAwakeTimes = newTimes
        return true
    end

    return false
end

return ModelWonderland